import React from 'react';

const ScreenFive = ({ dietGoal, handleDietGoalChange }) => {
  const dietOptions = [
    'Follow a specific diet (e.g. vegan)',
    'Weight loss',
    'Receive nutritional education',
    'Muscle Gain',
    'None of the above'
  ];

  const handleRadioChange = (event) => {
    handleDietGoalChange(event.target.value);
  };

  return (
    <div>
      <h2>What is your main dietary or fitness goal?</h2>
      <div className="form-group">
        {dietOptions.map((option, index) => (
          <div key={index} className="radio-group">
            <label>
              <input
                type="radio"
                name="dietGoal"
                value={option}
                checked={dietGoal === option}
                onChange={handleRadioChange}
              />
              {option}
            </label>
          </div>
        ))}
      </div>
    </div>
  );
};

export default ScreenFive;
